102	// RunViaServiceWith is the variant of RunViaService that accepts a pre-built
103	// DdxAgent so callers issuing many requests can reuse one service instance.
104	func RunViaServiceWith(ctx context.Context, svc agentlib.DdxAgent, workDir string, opts RunOptions) (*Result, error) {
105		if svc == nil {
106			return nil, fmt.Errorf("agent: nil service")
107		}
108		if ctx == nil {
109			ctx = context.Background()
110		}
111		if opts.Context != nil {
112			ctx = opts.Context
113		}
114	
115		// Resolve prompt either from inline text or PromptFile.
116		promptText := opts.Prompt
117		if opts.PromptFile != "" {
118			data, err := readPromptFileBounded(opts.PromptFile)
119			if err != nil {
120				return nil, fmt.Errorf("agent: read prompt file: %w", err)
121			}
122			promptText = string(data)
123		}
124		if promptText == "" {
125			return nil, fmt.Errorf("agent: prompt is required")
126		}
127	
128		wd := opts.WorkDir
129		if wd == "" {
130			wd = workDir
131		}
132		if wd == "" {
133			wd, _ = os.Getwd()
134		}
135	
136		idle := opts.Timeout
137		if idle <= 0 {
138			idle = time.Duration(DefaultTimeoutMS) * time.Millisecond
139		}
140		wall := opts.WallClock
141		if wall <= 0 {
142			wall = time.Duration(DefaultWallClockMS) * time.Millisecond
143		}
144	
145		logDir := opts.SessionLogDir
146		if logDir == "" {
147			logDir = ResolveLogDir(workDir, "")
148		}
149	
150		harness := opts.Harness
151		if harness == "" && opts.Provider != "" {
152			// Honour --provider as a harness alias when no harness is explicit
153			// (matches Runner.resolveHarness behaviour).
154			harness = opts.Provider
155		}
156	
157		req := agentlib.ServiceExecuteRequest{
158			Prompt:          promptText,
159			Model:           opts.Model,
160			Provider:        opts.Provider,
161			Harness:         harness,
162			ModelRef:        opts.ModelRef,
163			Reasoning:       agentlib.Reasoning(opts.Effort),
164			Permissions:     opts.Permissions,
165			WorkDir:         wd,
166			Timeout:         wall,
167			IdleTimeout:     idle,
168			ProviderTimeout: DefaultProviderRequestTimeout,
169			SessionLogDir:   logDir,
170			Metadata:        opts.Correlation,
171		}
172	
173		cancelCtx, cancel := context.WithCancel(ctx)
174		defer cancel()
175	
176		start := time.Now().UTC()
177		events, err := svc.Execute(cancelCtx, req)
178		if err != nil {
179			return nil, fmt.Errorf("agent: execute: %w", err)
180		}
181	
182		final, toolCalls, routing := drainServiceEvents(events)
183		finishedAt := time.Now().UTC()
184		elapsed := finishedAt.Sub(start)
185	
186		result := &Result{
187			Harness:    harness,
188			Model:      opts.Model,
189			DurationMS: int(elapsed.Milliseconds()),
190			ToolCalls:  toolCalls,
191		}
192		if routing != nil {
193			result.Provider = routing.Provider
194			if routing.Model != "" {
195				result.Model = routing.Model
196			}
197			if routing.Harness != "" {
198				result.Harness = routing.Harness
199			}
200		}
201		if final != nil {
202			// Normalized final text from the upstream harness (agent-32e8ff5e);
203			// reviewer verdict extraction now parses this instead of raw stream
204			// frames (ddx-7bc0c8d5).
205			result.Output = final.FinalText
206			if final.Usage != nil {
207				// v0.9.1: Usage fields became *int (nullable).
208				if final.Usage.InputTokens != nil {
209					result.InputTokens = *final.Usage.InputTokens
210				}
211				if final.Usage.OutputTokens != nil {
212					result.OutputTokens = *final.Usage.OutputTokens
213				}
214				if final.Usage.TotalTokens != nil {
215					result.Tokens = *final.Usage.TotalTokens
216				}
217			}
218			if final.CostUSD > 0 {
219				result.CostUSD = final.CostUSD
220			}
221			if final.RoutingActual != nil {
222				if result.Provider == "" {
223					result.Provider = final.RoutingActual.Provider
224				}
225				if final.RoutingActual.Model != "" {
226					result.Model = final.RoutingActual.Model
227				}
228			}
229			switch final.Status {
230			case "success", "":
231				// happy path
232			case "stalled":
233				result.ExitCode = 1
234				if final.Error != "" {
235					result.Error = "stalled: " + final.Error
236				} else {
237					result.Error = "stalled"
238				}
239			case "timed_out":
240				result.ExitCode = 1
241				result.Error = fmt.Sprintf("timeout after %v", wall.Round(time.Second))
242			case "cancelled":
243				result.ExitCode = 1
244				result.Error = "cancelled"
245			default:
246				result.ExitCode = 1
247				if final.Error != "" {
248					result.Error = final.Error
249				} else {
250					result.Error = final.Status
251				}
252			}
253			if final.SessionLogPath != "" {
254				result.AgentSessionID = final.SessionLogPath
255			}
256		}
257		entry := SessionIndexEntryFromResult(workDir, opts, result, start, finishedAt)
258		_ = AppendSessionIndex(ResolveLogDir(workDir, ""), entry, finishedAt)
259		return result, nil
260	}
