type AgentRunRuntime struct {
	Prompt                string
	PromptFile            string
	PromptSource          string
	Output                io.Writer
	Correlation           map[string]string
	Record                bool
	Replay                bool
	WorkDir               string
	EstimatedPromptTokens int
	RequiresTools         bool
	SessionLogDirOverride string
	// HarnessOverride, ModelOverride, and PermissionsOverride let a caller
	// pin one of the durable knobs from rcfg for this single invocation
	// without re-resolving the full ResolvedConfig. SD-024 step B22d-d:
	// execute-bead pins permissions=unrestricted; the post-merge reviewer
	// pins harness/model to the reviewer-tier selection.
	HarnessOverride     string
	ModelOverride       string
	PermissionsOverride string
}

// dispatchViaResolvedConfig is the internal SD-024 dispatch seam shared by
// execute-bead and the post-merge reviewer. It resolves how the agent
// invocation is executed (test-injected runner, pre-built service, or a
// fresh service constructed from projectRoot) and threads the durable
// knobs from rcfg with the per-invocation plumbing/intent from runtime.
//
// Resolution order:
//  1. runner (test injection seam) — used directly via runner.Run.
//  2. svc (pre-built service) — used via RunViaServiceWith.
//  3. Fallback: construct a fresh service via NewServiceFromWorkDir(projectRoot)
//     and dispatch via RunViaServiceWith.
//
// Override fields on runtime (HarnessOverride, ModelOverride,
// PermissionsOverride, SessionLogDirOverride) take precedence over the
// matching rcfg accessors when non-empty, so callers can pin one knob for
// a single invocation without re-resolving config.
func dispatchViaResolvedConfig(ctx context.Context, projectRoot string, svc agentlib.DdxAgent, runner AgentRunner, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
	harness := runtime.HarnessOverride
	if harness == "" {
		harness = rcfg.Harness()
	}
	model := runtime.ModelOverride
	if model == "" {
		model = rcfg.Model()
	}
	permissions := runtime.PermissionsOverride
	if permissions == "" {
		permissions = rcfg.Permissions()
	}
	sessionLogDir := runtime.SessionLogDirOverride
	if sessionLogDir == "" {
		sessionLogDir = rcfg.SessionLogDir()
	}
	opts := RunOptions{
		Context:       ctx,
		Harness:       harness,
		Prompt:        runtime.Prompt,
		PromptFile:    runtime.PromptFile,
		PromptSource:  runtime.PromptSource,
		Correlation:   runtime.Correlation,
		Model:         model,
		Provider:      rcfg.Provider(),
		ModelRef:      rcfg.ModelRef(),
		Effort:        rcfg.Effort(),
		Timeout:       rcfg.Timeout(),
		WallClock:     rcfg.WallClock(),
		WorkDir:       runtime.WorkDir,
		Permissions:   permissions,
		SessionLogDir: sessionLogDir,
	}
	if runner != nil {
		return runner.Run(opts)
	}
	if svc == nil {
		built, err := NewServiceFromWorkDir(projectRoot)
		if err != nil {
			return nil, fmt.Errorf("agent: build service: %w", err)
		}
		svc = built
	}
	return RunViaServiceWith(ctx, svc, projectRoot, opts)
}

// RunViaServiceWith is the variant of RunViaService that accepts a pre-built
// DdxAgent so callers issuing many requests can reuse one service instance.

